-- Table: checkout_sessions (18 rows)
CREATE TABLE IF NOT EXISTS stripe.checkout_sessions (
  _raw_data jsonb NOT NULL,
  _last_synced_at timestamptz,
  _updated_at timestamptz NOT NULL DEFAULT now(),
  _account_id text NOT NULL,
  id text NOT NULL,
  allow_promotion_codes boolean,
  amount_subtotal bigint,
  amount_total bigint,
  billing_address_collection text,
  cancel_url text,
  client_reference_id text,
  currency text,
  customer text,
  customer_email text,
  line_items jsonb,
  livemode boolean,
  locale text,
  metadata jsonb,
  mode text,
  object text,
  payment_intent text,
  payment_method_types jsonb,
  setup_intent text,
  shipping jsonb,
  shipping_address_collection jsonb,
  submit_type text,
  subscription text,
  success_url text,
  total_details jsonb
);

