-- Table: customers (25 rows)
CREATE TABLE IF NOT EXISTS stripe.customers (
  _raw_data jsonb NOT NULL,
  _last_synced_at timestamptz,
  _updated_at timestamptz NOT NULL DEFAULT now(),
  _account_id text NOT NULL,
  id text NOT NULL,
  address jsonb,
  balance bigint,
  created bigint,
  currency text,
  default_source text,
  deleted boolean,
  delinquent boolean,
  description text,
  discount jsonb,
  email text,
  invoice_prefix text,
  invoice_settings jsonb,
  livemode boolean,
  metadata jsonb,
  name text,
  next_invoice_sequence bigint,
  object text,
  phone text,
  preferred_locales jsonb,
  shipping jsonb,
  sources jsonb,
  subscriptions jsonb,
  tax_exempt text,
  tax_ids jsonb
);

