-- Table: payment_intents (40 rows)
CREATE TABLE IF NOT EXISTS stripe.payment_intents (
  _raw_data jsonb NOT NULL,
  _last_synced_at timestamptz,
  _updated_at timestamptz NOT NULL DEFAULT now(),
  _account_id text NOT NULL,
  id text NOT NULL,
  amount bigint,
  amount_capturable bigint,
  amount_received bigint,
  application text,
  application_fee_amount bigint,
  canceled_at bigint,
  cancellation_reason text,
  capture_method text,
  charges jsonb,
  client_secret text,
  confirmation_method text,
  created bigint,
  currency text,
  customer text,
  description text,
  invoice text,
  last_payment_error jsonb,
  livemode boolean,
  metadata jsonb,
  next_action jsonb,
  object text,
  on_behalf_of text,
  payment_method text,
  payment_method_options jsonb,
  payment_method_types jsonb,
  receipt_email text,
  review text,
  setup_future_usage text,
  shipping jsonb,
  statement_descriptor text,
  statement_descriptor_suffix text,
  status text,
  transfer_data jsonb,
