-- Table: payment_methods (30 rows)
CREATE TABLE IF NOT EXISTS stripe.payment_methods (
  _raw_data jsonb NOT NULL,
  _last_synced_at timestamptz,
  _updated_at timestamptz NOT NULL DEFAULT now(),
  _account_id text NOT NULL,
  id text NOT NULL,
  alipay jsonb,
  au_becs_debit jsonb,
  bacs_debit jsonb,
  bancontact jsonb,
  billing_details jsonb,
  card jsonb,
  card_present jsonb,
  created bigint,
  customer text,
  eps jsonb,
  fpx jsonb,
  giropay jsonb,
  ideal jsonb,
  interac_present jsonb,
  livemode boolean,
  metadata jsonb,
  object text,
  p24 jsonb,
  sepa_debit jsonb,
  type text
);

