-- Table: plans (11 rows)
CREATE TABLE IF NOT EXISTS stripe.plans (
  _raw_data jsonb NOT NULL,
  _last_synced_at timestamptz,
  _updated_at timestamptz NOT NULL DEFAULT now(),
  _account_id text NOT NULL,
  id text NOT NULL,
  active boolean,
  aggregate_usage text,
  amount bigint,
  amount_decimal text,
  billing_scheme text,
  created bigint,
  currency text,
  interval text,
  interval_count bigint,
  livemode boolean,
  metadata jsonb,
  nickname text,
  object text,
  product text,
  tiers jsonb,
  tiers_mode text,
  transform_usage jsonb,
  trial_period_days bigint,
  usage_type text
);

