-- Table: subscription_schedules (14 rows)
CREATE TABLE IF NOT EXISTS stripe.subscription_schedules (
  _raw_data jsonb NOT NULL,
  _last_synced_at timestamptz,
  _updated_at timestamptz NOT NULL DEFAULT now(),
  _account_id text NOT NULL,
  id text NOT NULL,
  canceled_at bigint,
  completed_at bigint,
  created bigint,
  current_phase jsonb,
  customer text,
  default_settings jsonb,
  end_behavior text,
  livemode boolean,
  metadata jsonb,
  object text,
  phases jsonb,
  released_at bigint,
  released_subscription text,
  status text,
  subscription text
);

