-- Table: subscriptions (20 rows)
CREATE TABLE IF NOT EXISTS stripe.subscriptions (
  _raw_data jsonb NOT NULL,
  _last_synced_at timestamptz,
  _updated_at timestamptz NOT NULL DEFAULT now(),
  _account_id text NOT NULL,
  id text NOT NULL,
  application_fee_percent numeric,
  billing_cycle_anchor bigint,
  billing_thresholds jsonb,
  cancel_at bigint,
  cancel_at_period_end boolean,
  canceled_at bigint,
  collection_method text,
  created bigint,
  current_period_end bigint,
  current_period_start bigint,
  customer text,
  days_until_due bigint,
  default_payment_method text,
  default_source text,
  default_tax_rates jsonb,
  discount jsonb,
  ended_at bigint,
  items jsonb,
  latest_invoice text,
  livemode boolean,
  metadata jsonb,
  next_pending_invoice_item_invoice bigint,
  object text,
  pause_collection jsonb,
  pending_invoice_item_interval jsonb,
  pending_setup_intent text,
  pending_update jsonb,
  quantity bigint,
  schedule text,
  start_date bigint,
  status text,
  transfer_data jsonb,
  trial_end bigint,
  trial_start bigint
);

